sp_widget.client_script:
function($scope, spModal, $rootScope, spUtil) {
	var c = this;

	// STRY0088168 - DTLV has a scroll bar that does not allow printing to be displayed correctly
	$scope.printReport = function(){
    var originalContents = document.body.innerHTML;
    var printReport= document.getElementById('printDiv').innerHTML;
    document.body.innerHTML = printReport;
    window.print();
		// window.print()
	window.location.reload();
    //document.body.innerHTML = originalContents;
	}	
}

