//------------------------------------------------------------------------------------------------------------------------

//------------------------------------------------------------------------------------------------------------------------
// 2.5.3 | 10.01.2020 | KT | UI  | STRY0059017: TLV –Stretch - Add a linked Table of Contents to the top of the Tree Level Object form
//------------------------------------------------------------------------------------------------------------------------


@media (min-width: 576px)
.dtlv {
    padding: 1.5rem;
    margin-right: 0;
    margin-left: 0;
    border-width: .2rem;
}


.spybody {
	height: 500px;
  overflow-y: scroll;
  //padding: 10px;
}

.nav {
    display: -ms-flexbox;
    display: flex;
    -ms-flex-wrap: wrap;
    flex-wrap: wrap;
    padding-left: 0;
    margin-bottom: 0;
    list-style: none;
}

.navbar {
    position: relative;
    display: -ms-flexbox;
    display: flex;
    -ms-flex-wrap: wrap;
    flex-wrap: wrap;
    -ms-flex-align: center;
    align-items: center;
    -ms-flex-pack: justify;
    justify-content: space-between;
    padding: .5rem 1rem;
}

.nav-pills .nav-link.active, .nav-pills .show>.nav-link {
    color: #fff;
    background-color: #007bff;
}

.nav-pills .nav-link {
    border-radius: .25rem;
}

.nav-link {
    display: block;
    padding: .5rem 1rem;
}

//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.02.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------

.glyphicon {
	margin-right: 10px !important;
}

.panel-heading {
  font-size: 16px !important;
}

.content {
  margin-left: 15px !important;
  margin-right: 20px !important;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CREATED BY: KARINA TORRES
// WIDGET BASE: N/A.
// LAST UPDATE: 08.25.20
//------------------------------------------------------------------------------------------------------------------------
// form functionality - URL parameter driven
(function($sp, input, data, options, gs) {
    /* populate the 'data' object */ /* e.g., data.table = $sp.getValue('table'); */

    data.sys_id = $sp.getParameter("sys_id");
    data.table = $sp.getParameter("table");
    data.view = 'sp';
    data.showFormView = "true";

    var gr = new GlideRecord('x_153465_discovert_route_task_instance');
    if (gr.get(data.sys_id)) data.task_tree_sys_id = gr.u_task_tree.sys_id.toString();


	//------------------------------------------------------------------------------------------------------------------------
    //  DOC. INT INTEGRATION - INITIALIZING VARIABLES 
    //------------------------------------------------------------------------------------------------------------------------
    var tDS = new taskerDocumentScripts();
    var currentAttachDocSettings = tDS.getAttachmentAndDocumentSettings(gr);
    data.SNAttachmentsON = currentAttachDocSettings.sNOWAttachmentsOn;
    data.DocIntON = currentAttachDocSettings.docIntDocumentsOn;

    //------------------------------------------------------------------------------------------------------------------------
    // Box 1:  Objective | Instructions
    //------------------------------------------------------------------------------------------------------------------------
    data.task_name = gr.task_name.toString();
		data.calchaschildren = gr.calchaschildren.toString();
    data.objective = gr.u_objective.getHTMLValue(4000).replace(/<\/?[^>]+(>|$)/g, "") + "" + gr.u_objective_sub_task.getHTMLValue(4000).replace(/<\/?[^>]+(>|$)/g, "");
    data.instructions = gr.instructions.getHTMLValue(4000).replace(/<\/?[^>]+(>|$)/g, ""); //gr.instructions.toString();


    //------------------------------------------------------------------------------------------------------------------------
    // Box 10: Task Tree Graph
    //------------------------------------------------------------------------------------------------------------------------

    var tasktreeGraph_Options = {
        table: data.table,
        sys_id: data.sys_id
    };

    data.tasktreeGraph = $sp.getWidget('discovertasker-recursivetasktreegraph', tasktreeGraph_Options);


    //------------------------------------------------------------------------------------------------------------------------
    // Box 3: Summary Card
    //------------------------------------------------------------------------------------------------------------------------

    var summarycard_Options = {
        table: data.table,
        title: 'Summary Card',
        show_systemfields: true,
        filter: 'taskernumber,number,suspense_date,classification,tasking_authority,primary_assignee,short_description,state,status,tasker_type,u_reviewer,u_task_requester,primary_assignee,assigned_to'
    };

    data.summarycard = $sp.getWidget('discovertasker-summarycard', summarycard_Options);


    //------------------------------------------------------------------------------------------------------------------------
    // Box 3: Sub Tasks
    //------------------------------------------------------------------------------------------------------------------------
	var filter = 'u_all_ancestors_tasksLIKE' + data.sys_id;
	var o = "number";
    var d = "asc";

    var subTasks_Options = {
        title: 'Subtasks',
        table: data.table,
        filter: filter,

        enable_filter: false,
        show_keywords: false,
        show_breadcrumbs: false,

        //view: 'SubTasks',
        fields: 'parent,taskernumber,number,tasker_type,short_description,calchaschildren,classification,state,status,suspense_date,primary_assignee,assigned_to,provide_response,decision,response', //,comments_and_work_notes',
        maximum_entries: 1000,
        display_field: 'number',
        glyph: 'pencil-square-o', //bell-slash-o',
        open_row_details_in_modal: true,
        o: o,
        d: d,
        color: 'primary'
    };

    data.subTasks = $sp.getWidget('discovertasker-widget-data-table', subTasks_Options); //widget-data-table //discovertasker-widget-data-table

    //------------------------------------------------------------------------------------------------------------------------
    // Box 3.5: Response Log
    //------------------------------------------------------------------------------------------------------------------------
    data.table_responseLog = 'x_153465_discovert_discover_tasker_response';
    var filter_responseLog = 'u_task=' + data.sys_id + '^ORu_task.u_all_ancestors_tasksLIKE' + data.sys_id;

    var o_responseLog = "u_task_number";
    var d_responseLog = "asc";

    var responseLog_Options = {
        title: 'Response Log',
        table: data.table_responseLog,
        filter: filter_responseLog,

        enable_filter: false,
        show_keywords: false,
        show_breadcrumbs: false,

        // Parent Task,Tasker Number, Number,Task Name,  Request Number, Request Type
        //view: 'ActivityLog',
        fields: 'u_task.parent,u_task.taskernumber,u_task_number,u_task.short_description,sys_created_on,u_primary_assignee,u_responded_by,u_role,u_action_taken',
        maximum_entries: 1000,
        //display_field: 'number',
        glyph: 'bullhorn',
        open_row_details_in_modal: true,
        o: o_responseLog,
        d: d_responseLog,
        color: 'primary'
    };

		data.subResponseLog = $sp.getWidget('discovertasker-widget-data-table', responseLog_Options); //widget-data-table //discovertasker-widget-data-table

    //------------------------------------------------------------------------------------------------------------------------
    // Box 4: Request Log
    //------------------------------------------------------------------------------------------------------------------------
    data.table_request = 'x_153465_discovert_tasker_requests';
    var filter_request = 'parent.u_all_ancestors_tasksLIKE' + data.sys_id;

    var o_request = "parent";
    var d_request = "asc";

    var subTasksRequests_Options = {
        title: 'Requests',
        table: data.table_request,
        filter: filter_request,

        enable_filter: false,
        show_keywords: false,
        show_breadcrumbs: false,

        // Parent Task,Tasker Number, Number,Task Name,  Request Number, Request Type
        //view: 'ActivityLog',
        fields: 'parent.taskernumber,parent.number,parent.short_description,number,u_request_type,u_request_comments,u_requested_by,u_requested,u_status,u_response,u_response_comments,u_responded_by,u_responded',
        maximum_entries: 1000,
        //display_field: 'number',
        glyph: 'bullhorn',
        open_row_details_in_modal: true,
        o: o_request,
        d: d_request,
        color: 'primary'
    };

    data.subTasksRequests = $sp.getWidget('discovertasker-widget-data-table', subTasksRequests_Options); //widget-data-table //discovertasker-widget-data-table

    //------------------------------------------------------------------------------------------------------------------------
    // Box 4: Activity Log
    //------------------------------------------------------------------------------------------------------------------------
    data.table_audit = 'x_153465_discovert_activity_view';
    var filter_audit = 'taskid_u_all_ancestors_tasksLIKE' + data.sys_id;
    //filter_audit = 'taskid_u_all_ancestors_tasksLIKE'+ data.sys_id+'^journalid_valueNOT LIKERequest has been';

    var o_audit = "taskid_number";
    var d_audit = "asc";

    var subTasksActivity_Options = {
        title: 'Activity Log',
        table: data.table_audit,
        filter: filter_audit,

        enable_filter: false,
        show_keywords: false,
        show_breadcrumbs: false,

        //view: 'ActivityLog',
        fields: 'taskid_parent,taskid_taskernumber,taskid_number,taskid_short_description,journalid_sys_created_by,journalid_sys_created_on,journalid_element,journalid_value',
        maximum_entries: 1000,
        //display_field: 'number',
        glyph: 'comment-o',
        open_row_details_in_modal: false,
        o: o_audit,
        d: d_audit,
        color: 'primary'
    };

    data.subTasksActivity = $sp.getWidget('discovertasker-widget-data-table', subTasksActivity_Options); //widget-data-table //discovertasker-widget-data-table


    //------------------------------------------------------------------------------------------------------------------------
    // Box 5: Key Data: Reports?
    //------------------------------------------------------------------------------------------------------------------------
    var progressBar_Options = {
        table: data.table,
        sys_id: data.sys_id
    };

    data.progressBar = $sp.getWidget('discovertasker-statesmultiplebar', progressBar_Options);

    var countStatusOnTime_Options = {
        title: 'On Time',
        table: data.table,
        filter: filter + '^status=Projected on time',
        color: 'success',
				glyph: 'bell-o'
    };

    data.countStatusOnTime = $sp.getWidget('tasker_count', countStatusOnTime_Options);


    var countStatusWarning_Options = {
        title: 'Warning',
        table: data.table,
        filter: filter + '^status=Warning',
        color: 'warning',
				glyph: 'calendar-o'
    };

    data.countStatusWarning = $sp.getWidget('tasker_count', countStatusWarning_Options);


    var countStatusCritical_Options = {
        title: 'Critical',
        table: data.table,
        filter: filter + '^status=Critical',
        color: 'danger',
				glyph: 'bell-slash-o'
    };

    data.countStatusCritical = $sp.getWidget('tasker_count', countStatusCritical_Options);

    //------------------------------------------------------------------------------------------------------------------------
    // Box 6: Shared Attachments
    //------------------------------------------------------------------------------------------------------------------------
    var sharedAttachTableName;
    var sharedAttachSys_ID;

    if (data.table == "x_153465_discovert_route_task_instance") {
        sharedAttachTableName = 'x_153465_discovert_task_tree';
        sharedAttachSys_ID = data.task_tree_sys_id;
    }

    var sharedAttachment_Options = {
        title: 'Shared Attachments',
        record_table: sharedAttachTableName,
        record_id: sharedAttachSys_ID,
        record_name: 'sharedAttachmentWidget'
    };

    data.sharedAttachment = $sp.getWidget('tasker_task_attachments', sharedAttachment_Options);

    //------------------------------------------------------------------------------------------------------------------------
    // Box 7: Shared Documents
    //------------------------------------------------------------------------------------------------------------------------
    var DocIntSharedDocsViewSysID = gs.getProperty('x_153465_discovert.DocIntSharedDocumentsViewSysIDTasks');
    data.isActive = true;

    var sharedDocumentsWidget_options = {
        title: 'Shared Documents',
        vw: DocIntSharedDocsViewSysID,
        mapRowSysId: data.sys_id.toString(),
        readonly_flag: data.isActive,
        lw_name: 'widgetDocIntegrationSharedDocs',
        color: 'primary'
    };

    data.sharedDocuments = $sp.getWidget('docint-list-items', sharedDocumentsWidget_options);


})($sp, input, data, options, gs);

//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// WIDGET BASE: N/A
//------------------------------------------------------------------------------------------------------------------------
